import React from 'react';
import { QRCodeSVG } from 'qrcode.react';

export default function InvitationQR({ guestName }) {
  // The value could be a unique URL or a JSON string with guest details
  const qrValue = `Wedding Pass: ${guestName} | Venue: Grand Palace`;

  return (
    <div className="bg-luxury-cream p-8 border-double border-4 border-luxury-gold rounded-lg text-center max-w-sm mx-auto my-10">
      <h4 className="font-serif text-2xl text-luxury-dark mb-2 italic">Digital Invitation</h4>
      <p className="text-[10px] uppercase tracking-tighter text-luxury-accent mb-6">Present this at the entrance</p>
      
      <div className="bg-white p-4 inline-block shadow-inner mb-6">
        <QRCodeSVG 
          value={qrValue} 
          size={180}
          fgColor="#1A1A1B"
          level="H"
          includeMargin={true}
        />
      </div>

      <div className="text-luxury-dark font-serif text-xl border-t border-luxury-gold/30 pt-4">
        {guestName}
      </div>
      <p className="text-[10px] mt-2 opacity-60 uppercase">Valid for 04.12.2026</p>
    </div>
  );
}
